import{_ as t,a as e,i as o,o as l}from"./chunks/framework.CXVo2Jqr.js";const g=JSON.parse('{"title":"扩展汉字字根显示说明","description":"","frontmatter":{},"headers":[],"relativePath":"字根显示说明.md","filePath":"字根显示说明.md","lastUpdated":1773588811000}'),n={name:"字根显示说明.md"};function r(i,a,s,h,d,u){return l(),e("div",null,a[0]||(a[0]=[o(`<h1 id="扩展汉字字根显示说明" tabindex="-1">扩展汉字字根显示说明 <a class="header-anchor" href="#扩展汉字字根显示说明" aria-label="Permalink to &quot;扩展汉字字根显示说明&quot;">​</a></h1><h2 id="问题说明" tabindex="-1">问题说明 <a class="header-anchor" href="#问题说明" aria-label="Permalink to &quot;问题说明&quot;">​</a></h2><p>某些字根（如&quot;𠂊&quot;）属于<strong>CJK 扩展 B 区</strong>字符（Unicode: U+20000-U+2A6DF），这些字符需要特殊字体支持才能正确显示。</p><h2 id="字符信息" tabindex="-1">字符信息 <a class="header-anchor" href="#字符信息" aria-label="Permalink to &quot;字符信息&quot;">​</a></h2><ul><li><strong>字符</strong>：𠂊</li><li><strong>Unicode</strong>: U+2008A</li><li><strong>所属区域</strong>: CJK 扩展 B 区</li><li><strong>读音</strong>: 可能是&quot;撇&quot;的变体</li><li><strong>用途</strong>: 汉字部件，常见于&quot;危&quot;等字的顶部</li></ul><h2 id="支持的扩展区域" tabindex="-1">支持的扩展区域 <a class="header-anchor" href="#支持的扩展区域" aria-label="Permalink to &quot;支持的扩展区域&quot;">​</a></h2><p>本项目已支持以下 CJK 扩展区域：</p><p>✅ <strong>CJK 扩展 B 区</strong> (U+20000-U+2A6DF) - 42,711 字 ✅ <strong>CJK 扩展 C 区</strong> (U+2A700-U+2B73F) - 3,158 字 ✅ <strong>CJK 扩展 D 区</strong> (U+2B740-U+2B81F) - 222 字 ✅ <strong>CJK 扩展 E 区</strong> (U+2B820-U+2CEAF) - 5,762 字 ✅ <strong>CJK 扩展 F 区</strong> (U+2CEB0-U+2EBEF) - 7,473 字 ✅ <strong>CJK 扩展 G 区</strong> (U+30000-U+3134F) - 4,939 字 ✅ <strong>CJK 扩展 H 区</strong> (U+31350-U+323AF) - 4,192 字 ✅ <strong>CJK 扩展 I 区</strong> (U+323B0-U+32FFF) - 正在添加</p><h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2><h3 id="方案一-安装支持扩展汉字的字体-推荐" tabindex="-1">方案一：安装支持扩展汉字的字体（推荐） <a class="header-anchor" href="#方案一-安装支持扩展汉字的字体-推荐" aria-label="Permalink to &quot;方案一：安装支持扩展汉字的字体（推荐）&quot;">​</a></h3><h4 id="windows-系统" tabindex="-1">Windows 系统 <a class="header-anchor" href="#windows-系统" aria-label="Permalink to &quot;Windows 系统&quot;">​</a></h4><ol><li><p><strong>下载字体</strong></p><ul><li><a href="https://www.babelstone.co.uk/Software/Download.html" target="_blank" rel="noreferrer">BabelStone Han</a> - <strong>最全面</strong>，支持扩展 B/C/D/E/F/G/H</li><li><a href="http://fonts.jp/hanazono/" target="_blank" rel="noreferrer">花园明朝体 (Hanazono)</a> - 免费开源，支持扩展 B/C/D/E/F</li><li><a href="https://moji.or.jp/ipafont/" target="_blank" rel="noreferrer">IPA 明朝</a> - 日本 IPA 字体</li><li><strong>Windows 10/11 自带</strong>：SimSun-ExtB (宋体扩展 B)</li></ul></li><li><p><strong>安装步骤</strong></p><ul><li>下载字体文件（.ttf 或 .otf）</li><li>右键点击字体文件 → &quot;为所有用户安装&quot;</li><li>重启浏览器</li></ul></li></ol><h4 id="macos-系统" tabindex="-1">macOS 系统 <a class="header-anchor" href="#macos-系统" aria-label="Permalink to &quot;macOS 系统&quot;">​</a></h4><p>macOS 默认支持大部分扩展汉字，如无法显示：</p><ul><li>下载 <a href="https://github.com/adobe-fonts/source-han-sans" target="_blank" rel="noreferrer">Source Han Sans</a></li><li>或 <a href="https://fonts.google.com/noto" target="_blank" rel="noreferrer">Noto Sans CJK</a></li></ul><h4 id="linux-系统" tabindex="-1">Linux 系统 <a class="header-anchor" href="#linux-系统" aria-label="Permalink to &quot;Linux 系统&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ubuntu/Debian</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fonts-noto-cjk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fonts-babelstone</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Arch Linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> noto-fonts-cjk</span></span></code></pre></div><h3 id="方案二-使用在线字体-无需安装" tabindex="-1">方案二：使用在线字体（无需安装） <a class="header-anchor" href="#方案二-使用在线字体-无需安装" aria-label="Permalink to &quot;方案二：使用在线字体（无需安装）&quot;">​</a></h3><p>项目已经配置了字体回退机制，会优先使用系统字体，如果系统没有则尝试加载在线字体。</p><h3 id="方案三-使用备用显示方式" tabindex="-1">方案三：使用备用显示方式 <a class="header-anchor" href="#方案三-使用备用显示方式" aria-label="Permalink to &quot;方案三：使用备用显示方式&quot;">​</a></h3><p>如果确实无法显示，可以考虑：</p><ol><li>使用拼音或描述代替</li><li>使用图片展示</li><li>使用相似字符代替</li></ol><h2 id="字根分类" tabindex="-1">字根分类 <a class="header-anchor" href="#字根分类" aria-label="Permalink to &quot;字根分类&quot;">​</a></h2><h3 id="已完全支持的字根区域" tabindex="-1">已完全支持的字根区域 <a class="header-anchor" href="#已完全支持的字根区域" aria-label="Permalink to &quot;已完全支持的字根区域&quot;">​</a></h3><p>✅ <strong>基本汉字</strong> (U+4E00-U+9FFF) - 所有系统默认支持 ✅ <strong>CJK 扩展 A</strong> (U+3400-U+4DBF) - 大部分系统支持 ✅ <strong>偏旁部首</strong> (U+2F00-U+2FDF) - 大部分系统支持 ✅ <strong>康熙部首</strong> (U+2F00-U+2FDF) - 大部分系统支持</p><h3 id="需要特殊字体支持的字根区域" tabindex="-1">需要特殊字体支持的字根区域 <a class="header-anchor" href="#需要特殊字体支持的字根区域" aria-label="Permalink to &quot;需要特殊字体支持的字根区域&quot;">​</a></h3><p>⚠️ <strong>CJK 扩展 B</strong> (U+20000-U+2A6DF) - 需要 BabelStone Han 等字体 ⚠️ <strong>CJK 扩展 C</strong> (U+2A700-U+2B73F) - 需要 BabelStone Han 或 Hanazono ⚠️ <strong>CJK 扩展 D</strong> (U+2B740-U+2B81F) - 需要 BabelStone Han 或 Hanazono ⚠️ <strong>CJK 扩展 E</strong> (U+2B820-U+2CEAF) - 需要 BabelStone Han 或 Hanazono ⚠️ <strong>CJK 扩展 F</strong> (U+2CEB0-U+2EBEF) - 需要 BabelStone Han 或 Hanazono ⚠️ <strong>CJK 扩展 G</strong> (U+30000-U+3134F) - 需要最新 BabelStone Han ⚠️ <strong>CJK 扩展 H</strong> (U+31350-U+323AF) - 需要最新 BabelStone Han ⚠️ <strong>私用区</strong> (U+E000-U+F8FF) - 无标准字形</p><h2 id="推荐字体优先级" tabindex="-1">推荐字体优先级 <a class="header-anchor" href="#推荐字体优先级" aria-label="Permalink to &quot;推荐字体优先级&quot;">​</a></h2><h3 id="完整支持-推荐" tabindex="-1">完整支持（推荐） <a class="header-anchor" href="#完整支持-推荐" aria-label="Permalink to &quot;完整支持（推荐）&quot;">​</a></h3><ol><li><p><strong>BabelStone Han</strong> - 支持最全（强烈推荐）</p><ul><li>支持：扩展 B/C/D/E/F/G/H 区</li><li>下载：<a href="https://www.babelstone.co.uk/Software/Download.html" target="_blank" rel="noreferrer">https://www.babelstone.co.uk/Software/Download.html</a></li></ul></li><li><p><strong>花园明朝体 (Hanazono)</strong> - 免费开源</p><ul><li>支持：扩展 B/C/D/E/F 区</li><li>下载：<a href="http://fonts.jp/hanazono/" target="_blank" rel="noreferrer">http://fonts.jp/hanazono/</a></li></ul></li><li><p><strong>Windows 10/11 自带字体</strong></p><ul><li>SimSun-ExtB (宋体扩展 B)</li><li>SimSun-ExtC (宋体扩展 C)</li><li>SimSun-ExtD (宋体扩展 D)</li><li>位置：C:\\Windows\\Fonts\\</li></ul></li></ol><h3 id="部分支持" tabindex="-1">部分支持 <a class="header-anchor" href="#部分支持" aria-label="Permalink to &quot;部分支持&quot;">​</a></h3><ol start="4"><li><p><strong>Noto Sans CJK SC</strong> - Google 官方</p><ul><li>支持：基本汉字 + 扩展 A/B 区</li></ul></li><li><p><strong>Source Han Sans SC</strong> - Adobe 官方</p><ul><li>支持：基本汉字 + 扩展 A/B 区</li></ul></li><li><p><strong>Microsoft YaHei</strong> - Windows 默认</p><ul><li>支持：基本汉字 + 扩展 A 区</li></ul></li></ol><h2 id="验证是否支持" tabindex="-1">验证是否支持 <a class="header-anchor" href="#验证是否支持" aria-label="Permalink to &quot;验证是否支持&quot;">​</a></h2><p>访问页面后，检查以下字符是否能显示：</p><h3 id="扩展-b-区测试" tabindex="-1">扩展 B 区测试 <a class="header-anchor" href="#扩展-b-区测试" aria-label="Permalink to &quot;扩展 B 区测试&quot;">​</a></h3><ul><li>𠂊 (U+2008A) - 扩展 B 区</li><li>𠄌 (U+2010C) - 扩展 B 区</li></ul><h3 id="扩展-c-区测试" tabindex="-1">扩展 C 区测试 <a class="header-anchor" href="#扩展-c-区测试" aria-label="Permalink to &quot;扩展 C 区测试&quot;">​</a></h3><ul><li>(U+2A600) - 扩展 C 区</li><li>𪘁 (U+2A601) - 扩展 C 区</li></ul><h3 id="扩展-d-区测试" tabindex="-1">扩展 D 区测试 <a class="header-anchor" href="#扩展-d-区测试" aria-label="Permalink to &quot;扩展 D 区测试&quot;">​</a></h3><ul><li>𫚄 (U+2B684) - 扩展 D 区</li></ul><h3 id="扩展-e-区测试" tabindex="-1">扩展 E 区测试 <a class="header-anchor" href="#扩展-e-区测试" aria-label="Permalink to &quot;扩展 E 区测试&quot;">​</a></h3><ul><li>(U+2B696) - 扩展 E 区</li></ul><h3 id="扩展-f-区测试" tabindex="-1">扩展 F 区测试 <a class="header-anchor" href="#扩展-f-区测试" aria-label="Permalink to &quot;扩展 F 区测试&quot;">​</a></h3><ul><li>(U+2B7C5) - 扩展 F 区</li></ul><p>如果显示为方框或问号，说明需要安装字体。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么有些字根显示为方框" tabindex="-1">Q: 为什么有些字根显示为方框？ <a class="header-anchor" href="#q-为什么有些字根显示为方框" aria-label="Permalink to &quot;Q: 为什么有些字根显示为方框？&quot;">​</a></h3><p>A: 系统字体不支持该 Unicode 字符，需要安装扩展汉字字体。</p><h3 id="q-安装字体后仍然无法显示" tabindex="-1">Q: 安装字体后仍然无法显示？ <a class="header-anchor" href="#q-安装字体后仍然无法显示" aria-label="Permalink to &quot;Q: 安装字体后仍然无法显示？&quot;">​</a></h3><p>A: 请重启浏览器，清除缓存。</p><h3 id="q-移动端如何支持" tabindex="-1">Q: 移动端如何支持？ <a class="header-anchor" href="#q-移动端如何支持" aria-label="Permalink to &quot;Q: 移动端如何支持？&quot;">​</a></h3><p>A: iOS 9+ 和 Android 5.0+ 默认支持大部分扩展汉字。</p><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li><a href="https://en.wikipedia.org/wiki/CJK_Unified_Ideographs_Extension_B" target="_blank" rel="noreferrer">Unicode CJK 扩展区</a></li><li><a href="https://www.babelstone.co.uk/Software/Download.html" target="_blank" rel="noreferrer">BabelStone 字体下载</a></li><li><a href="http://fonts.jp/hanazono/" target="_blank" rel="noreferrer">花园明朝体</a></li><li><a href="https://www.unicode.org/cgi-bin/GetUnihanData.pl?codepoint=2008A" target="_blank" rel="noreferrer">字源查询</a></li></ul>`,54)]))}const c=t(n,[["render",r]]);export{g as __pageData,c as default};
